'use client';
/* eslint-disable react-hooks/incompatible-library */

import type { CSSProperties } from 'react';
import { Fragment, useImperativeHandle, useRef } from 'react';
import { useVirtualizer } from '@tanstack/react-virtual';
import { Slot } from '@radix-ui/react-slot';
import { cn } from '@/lib/utils';
import { virtualizerVariants } from './virtualizer-variants';
import type { VirtualGridProps, VirtualizerGrid } from './types';

const VirtualGrid = <
  T,
  TScrollElement extends HTMLDivElement = HTMLDivElement,
  TItemElement extends Element = Element
>(
  props: VirtualGridProps<T, TScrollElement, TItemElement>
) => {
  const {
    data,
    columns,
    rowHeight,
    columnWidth,
    width,
    height,
    ref,
    className,
    classNames,
    style,
    containerProps,
    keyExtractor,
    onChange,
    onScroll,
    renderCell,
    columnProps,
    ...rest
  } = props;

  const { root, inner } = virtualizerVariants();

  const mergedRootCls = cn(root(), className ?? classNames?.root);
  const innerCls = cn(inner(), classNames?.inner);

  const rootRef = useRef<HTMLDivElement>(null);

  const rowCount = Math.ceil(data.length / columns);

  const getRowSize = (index: number) =>
    typeof rowHeight === 'function' ? rowHeight(index) : rowHeight;

  const getColumnSize = (index: number) =>
    typeof columnWidth === 'function' ? columnWidth(index) : columnWidth;

  // Vertical virtualization: rows
  const rowVirtualizer = useVirtualizer<TScrollElement, TItemElement>({
    getScrollElement: () => rootRef.current as TScrollElement,
    count: rowCount,
    estimateSize: getRowSize,
    // Row virtualizer onChange serves as primary onChange/onScroll callback
    onChange: (instance, sync) => {
      onChange?.(instance, sync);
      onScroll?.(instance.scrollOffset ?? 0);
    },
    ...rest
  });

  // Horizontal virtualization: columns
  const columnVirtualizer = useVirtualizer<TScrollElement, TItemElement>({
    getScrollElement: () => rootRef.current as TScrollElement,
    count: columns,
    estimateSize: getColumnSize,
    horizontal: true,
    ...columnProps
  });

  const containerStyle: CSSProperties = {
    height,
    width,
    overflow: 'auto',
    ...style
  };

  const innerStyle: CSSProperties = {
    position: 'relative',
    height: rowVirtualizer.getTotalSize(),
    width: columnVirtualizer.getTotalSize()
  };

  useImperativeHandle(ref, () => {
    return {
      containerRef: rootRef.current as TScrollElement,
      rowVirtualizer,
      columnVirtualizer,
      ...rowVirtualizer
    } as unknown as VirtualizerGrid<TScrollElement, TItemElement>;
  }, [rowVirtualizer, columnVirtualizer, rootRef]);

  return (
    <div
      {...containerProps}
      className={mergedRootCls}
      ref={rootRef}
      style={containerStyle}
    >
      <div
        className={innerCls}
        style={innerStyle}
      >
        {rowVirtualizer.getVirtualItems().map(virtualRow => (
          <Fragment key={virtualRow.index}>
            {columnVirtualizer.getVirtualItems().map((virtualColumn) => {
              const rowIndex = virtualRow.index;
              const colIndex = virtualColumn.index;
              const dataIndex = rowIndex * columns + colIndex;

              if (dataIndex >= data.length)
                return null;

              const item = data[dataIndex];

              const cellStyle: CSSProperties = {
                position: 'absolute',
                top: 0,
                left: 0,
                width: virtualColumn.size,
                height: virtualRow.size,
                transform: `translateX(${virtualColumn.start}px) translateY(${virtualRow.start}px)`
              };

              const key = keyExtractor
                ? typeof keyExtractor === 'function'
                  ? keyExtractor(item, rowIndex * colIndex)
                  : (item as any)[keyExtractor]
                : `${rowIndex}-${colIndex}`;

              return (
                <Slot
                  key={String(key)}
                  style={cellStyle}
                >
                  {renderCell(item, rowIndex, colIndex)}
                </Slot>
              );
            })}
          </Fragment>
        ))}
      </div>
    </div>
  );
};

export default VirtualGrid;

'use client';
/* eslint-disable react-hooks/incompatible-library */
import type { CSSProperties, Ref } from 'react';
import { Fragment, useImperativeHandle, useRef } from 'react';
import { useVirtualizer } from '@tanstack/react-virtual';
import { Slot } from '@radix-ui/react-slot';
import { cn } from '@/lib/utils';
import { virtualizerVariants } from './virtualizer-variants';
import type { VirtualizerList, VirtualListProps } from './types';

/**
 * A styled virtual list component for efficiently rendering large lists.
 *
 * @example
 * ```tsx
 * // Basic usage
 * <VirtualList
 *   data={items}
 *   height={400}
 *   itemSize={50}
 *   keyExtractor='id'
 *   renderItem={(item) => (
 *     <div className="flex items-center px-4 border-b">
 *       {item.name}
 *     </div>
 *   )}
 * />
 *
 * // With custom styling
 * <VirtualList
 *   data={items}
 *   height={400}
 *   itemSize={50}
 *   keyExtractor={(item, index) => item.id}
 *   classNames={{
 *     root: 'border rounded-lg',
 *     item: 'hover:bg-accent'
 *   }}
 *   renderItem={(item, index) => (
 *     <div>
 *       {item.name}
 *     </div>
 *   )}
 * />
 * ```
 */
const VirtualList = <T, TScrollElement extends HTMLDivElement = HTMLDivElement, TItemElement extends Element = HTMLDivElement>(props: VirtualListProps<T, TScrollElement, TItemElement>) => {
  const { classNames, style, data, onChange, onScroll, className, horizontal, itemSize, renderItem, width, height, keyExtractor, containerProps, ref, dynamic, ...rest } = props;

  const { root, inner } = virtualizerVariants();

  const mergedCls = cn(root(), className || classNames?.root);

  const innerCls = cn(inner(), classNames?.inner);

  const rootRef = useRef<HTMLDivElement>(null);

  function getEstimateSize(index: number) {
    if (typeof itemSize === 'function') {
      return itemSize(index);
    }

    return itemSize;
  }

  const elementVirtualizer = useVirtualizer<TScrollElement, TItemElement>({
    getScrollElement: () => rootRef.current as TScrollElement,
    count: data.length,
    estimateSize: getEstimateSize,
    horizontal,
    onChange: (instance, sync) => {
      onChange?.(instance, sync);
      onScroll?.(instance.scrollOffset ?? 0);
    },
    ...rest
  });

  const containerStyle: CSSProperties = {
    height: horizontal ? height : height ?? '100%',
    width: horizontal ? (width ?? '100%') : width,
    overflow: 'auto',
    contain: 'strict',
    ...style
  };

  const items = elementVirtualizer.getVirtualItems();
  const totalSize = elementVirtualizer.getTotalSize();

  const innerStyle: CSSProperties = horizontal
    ? {
      width: totalSize,
      height: '100%',
      position: 'relative'
    }
    : {
      height: totalSize,
      width: '100%',
      position: 'relative'
    };

  useImperativeHandle(ref, () => {
    return {
      containerRef: rootRef.current as TScrollElement,
      ...elementVirtualizer
    } as unknown as VirtualizerList<TScrollElement, TItemElement>;
  }, [elementVirtualizer, rootRef]);

  const content = () => {
    if (dynamic) {
      const Comp = horizontal ? Fragment : 'div';

      const dynamicContent = (
        <Comp
          {...(horizontal
            ? {}
            : {
              style: {
                position: 'absolute' as const,
                top: 0,
                left: 0,
                width: '100%',
                transform: `translateY(${items[0]?.start ?? 0}px)`
              }
            })}
        >
          {items.map((virtualItem) => {
            const item = data[virtualItem.index];

            const key = keyExtractor ? typeof keyExtractor === 'function' ? keyExtractor(item, virtualItem.index) : item[keyExtractor] : virtualItem.index;
            return (
              <div
                data-index={virtualItem.index}
                key={String(key)}
                ref={elementVirtualizer.measureElement as Ref<HTMLDivElement>}
                style={horizontal
                  ? {
                    position: 'absolute',
                    top: 0,
                    left: 0,
                    height: '100%',
                    transform: `translateX(${virtualItem.start}px)`
                  }
                  : undefined}
              >
                {renderItem({
                  item,
                  index: virtualItem.index,
                  virtualItem,
                  virtualizer: elementVirtualizer
                })}
              </div>

            );
          })}
        </Comp>
      );
      return dynamicContent;
    }
    return items.map((virtualItem) => {
      const item = data[virtualItem.index];

      const itemStyle: CSSProperties = horizontal
        ? {
          position: 'absolute',
          top: 0,
          left: 0,
          height: '100%',
          width: `${virtualItem.size}px`,
          transform: `translateX(${virtualItem.start}px)`
        }
        : {
          position: 'absolute',
          top: 0,
          left: 0,
          width: '100%',
          height: `${virtualItem.size}px`,
          transform: `translateY(${virtualItem.start}px)`
        };

      const key = keyExtractor ? typeof keyExtractor === 'function' ? keyExtractor(item, virtualItem.index) : item[keyExtractor] : virtualItem.index;

      return (
        <Slot
          key={String(key)}
          style={itemStyle}
        >
          {renderItem({
            item,
            index: virtualItem.index,
            virtualItem,
            virtualizer: elementVirtualizer
          })}
        </Slot>
      );
    }); ;
  };

  return (
    <div
      {...containerProps}
      className={mergedCls}
      ref={rootRef}
      style={containerStyle}
    >
      <div
        className={innerCls}
        style={innerStyle}
      >
        {content()}
      </div>
    </div>
  );
};

export default VirtualList;

import { useVirtualizer, useWindowVirtualizer } from '@tanstack/react-virtual';

export { useVirtualizer, useWindowVirtualizer };

export { default as VirtualList } from './VirtualList';
export { default as VirtualGrid } from './VirtualGrid';

export * from './types';

import type { ComponentPropsWithoutRef, CSSProperties, ReactNode, Ref } from 'react';
import type { VirtualizerOptions, Virtualizer, PartialKeys, VirtualItem } from '@tanstack/react-virtual';
import type { ClassValue, StyledComponentProps } from '@/types/shared';
import type { VirtualizerSlots } from './virtualizer-variants';

export type VirtualizerClassNames = Partial<Record<VirtualizerSlots, ClassValue>>;

export interface VirtualizerList<TScrollElement extends HTMLDivElement = HTMLDivElement, TItemElement extends Element = Element>extends Virtualizer<TScrollElement, TItemElement> {
  containerRef: TScrollElement;
}

export interface VirtualizerGrid<TScrollElement extends HTMLDivElement = HTMLDivElement, TItemElement extends Element = Element>extends Virtualizer<TScrollElement, TItemElement> {
  containerRef: Ref<TScrollElement>;
  rowVirtualizer: VirtualizerList<TScrollElement, TItemElement>;
  columnVirtualizer: VirtualizerList<TScrollElement, TItemElement>;
}

export type VirtualizerBaseOptions<TScrollElement extends HTMLDivElement = HTMLDivElement, TItemElement extends Element = Element> = PartialKeys<VirtualizerOptions<TScrollElement, TItemElement>, 'observeElementRect' | 'observeElementOffset' | 'scrollToFn'>;

export interface VirtualListItem<T, TScrollElement extends HTMLDivElement = HTMLDivElement, TItemElement extends Element = Element> {
  item: T;
  index: number;
  virtualItem: VirtualItem;
  virtualizer: Virtualizer<TScrollElement, TItemElement>;
}

export interface VirtualizerProps<T, TScrollElement extends HTMLDivElement, TItemElement extends Element> extends Omit<VirtualizerBaseOptions<TScrollElement, TItemElement>, 'count' | 'estimateSize' | 'getScrollElement'> {
  /**
   * Custom class names for component slots
   */
  classNames?: VirtualizerClassNames;
  /**
   * Custom class name for the component
   */
  className?: ClassValue;
  /**
   * Data array to virtualize
   */
  data: T[];
  /**
   * Height of the container (for vertical lists)
   */
  height?: number | string;
  /**
   * Width of the container (for horizontal lists)
   */
  width?: number | string;

  /**
   * Props for the root <div>
   */
  containerProps?: StyledComponentProps<Omit<ComponentPropsWithoutRef<'div'>, 'style'>>;
  /**
   * Style for the container
   */
  style?: CSSProperties;
  /**
   * Callback when scroll position changes
   */
  onScroll?: (offset: number) => void;
  /**
   * Function to extract the key from the item
   */
  keyExtractor?: keyof T | ((item: T, index: number) => string);
}

export interface VirtualListProps<T, TScrollElement extends HTMLDivElement, TItemElement extends Element> extends VirtualizerProps<T, TScrollElement, TItemElement> {
  /**
   * Whether to use dynamic rendering
   */
  dynamic?: boolean;
  /**
   * Render function for each item
   */
  renderItem: (props: VirtualListItem<T, TScrollElement, TItemElement>) => ReactNode;
  /**
   * Reference to the virtualizer instance
   */
  ref?: Ref<VirtualizerList<TScrollElement, TItemElement> | null>;
  /**
   * Estimated item size
   */
  itemSize: number | ((index: number) => number);
}

export interface VirtualGridProps<T, TScrollElement extends HTMLDivElement, TItemElement extends Element> extends VirtualizerProps<T, TScrollElement, TItemElement> {
  /**
   * Render function for each grid cell
   */
  renderCell: (
    item: T,
    rowIndex: number,
    colIndex: number
  ) => ReactNode;
  /**
   * Number of columns per row
   */
  columns: number;

  /**
   * Row height: fixed value or function that calculates height per row
   */
  rowHeight: number | ((rowIndex: number) => number);

  /**
   * Column width: fixed value or function that calculates width per column
   */
  columnWidth: number | ((colIndex: number) => number);

  /**
   * Additional props for the column virtualizer
   */
  columnProps?: Omit<VirtualizerOptions<TScrollElement, TItemElement>, 'count' | 'estimateSize' | 'getScrollElement' | 'horizontal'>;
  /**
   * Reference to the virtualizer instance
   */
  ref?: Ref<VirtualizerGrid<TScrollElement, TItemElement> | null>;
}

import { tv } from 'tailwind-variants';

export const virtualizerVariants = tv({
  slots: {
    inner: '',
    root: 'scrollbar-thin scrollbar-thumb-accent scrollbar-track-transparent'
  }
});

export type VirtualizerSlots = keyof typeof virtualizerVariants.slots;
